    "160": {
      "ibnukatsir": "Tafsir Ibnu Katsir (Ringkas) / Fathul Karim Mukhtashar Tafsir al-Qur'an al-'Adzhim, karya Syaikh Prof. Dr. Hikmat bin Basyir bin Yasin, professor fakultas al-Qur'an Univ Islam MadinahAyat 160-164 Allah SWT berfirman seraya meb=mberitahukan tentang hamba dan rasulNya, nabi Lut. Dia adalah Luth bin Haran bin Azar yang merupakan keponakan nabi Ibrahim. Allah SWT mengutusnya kepada suatu kaum yang besar di masa hidup nabi Ibrahim. Mereka tinggal di Sodom dan kota-kota yang ada di sekitarnya yang dibinasakan Allah, lalu Allah mengubah tempat tinggal mereka menjadi danau yang aromanya busuk dan kotor, yang terkenal di negeri Al-Ghaur di sebelah bukit-bukit Baitul Maqdis. Nabi Luth menyeru mereka untuk menyembah hanya kepada Allah, tidak ada sekutu bagiNya, dan hendaknya mereka taat kepada rasul mereka yang diutus Allah kepada mereka. dan melarang mereka dari perbuatan durhaka kepada Allah dan melakukan perbuatan yang belum pernah ada seorangpun di dunia yang melakukannya selain mereka, yaitu menggauli laki-laki, bukan wanita. Oleh karena itu Allah berfirman",
      "jalalain": "Tafsir Jalalain tidak tersedia untuk ayat ini.",
      "quraish": "Tafsir Quraish Shihab tidak tersedia untuk ayat ini."
    },
    "161": {
      "ibnukatsir": "Tafsir Ibnu Katsir (Ringkas) / Fathul Karim Mukhtashar Tafsir al-Qur'an al-'Adzhim, karya Syaikh Prof. Dr. Hikmat bin Basyir bin Yasin, professor fakultas al-Qur'an Univ Islam MadinahAyat 160-164 Allah SWT berfirman seraya meb=mberitahukan tentang hamba dan rasulNya, nabi Lut. Dia adalah Luth bin Haran bin Azar yang merupakan keponakan nabi Ibrahim. Allah SWT mengutusnya kepada suatu kaum yang besar di masa hidup nabi Ibrahim. Mereka tinggal di Sodom dan kota-kota yang ada di sekitarnya yang dibinasakan Allah, lalu Allah mengubah tempat tinggal mereka menjadi danau yang aromanya busuk dan kotor, yang terkenal di negeri Al-Ghaur di sebelah bukit-bukit Baitul Maqdis. Nabi Luth menyeru mereka untuk menyembah hanya kepada Allah, tidak ada sekutu bagiNya, dan hendaknya mereka taat kepada rasul mereka yang diutus Allah kepada mereka. dan melarang mereka dari perbuatan durhaka kepada Allah dan melakukan perbuatan yang belum pernah ada seorangpun di dunia yang melakukannya selain mereka, yaitu menggauli laki-laki, bukan wanita. Oleh karena itu Allah berfirman Mau pahala jariyah & rezeki berlimpah? Klik di sini sekarang!",
      "jalalain": "Tafsir Jalalain tidak tersedia untuk ayat ini.",
      "quraish": "Tafsir Quraish Shihab tidak tersedia untuk ayat ini."
    },
